import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { useNotesList } from '@/composables/useNotesList';

describe('useNotesList', () => {
  const mockGetItem = vi.fn();

  beforeEach(() => {
    // Mock localStorage.getItem which is commonly used in note list implementations
    vi.stubGlobal('localStorage', {
      getItem: mockGetItem,
      setItem: vi.fn(),
      removeItem: vi.fn(),
      clear: vi.fn(),
    });
  });

  afterEach(() => {
    vi.restoreAllMocks();
    mockGetItem.mockReset();
  });

  it('should handle happy path and return an array of notes when storage contains data', () => {
    const storedNotes = JSON.stringify([
      { id: 1, title: 'Note 1', content: 'Content 1' },
      { id: 2, title: 'Note 2', content: 'Content 2' },
    ]);
    mockGetItem.mockReturnValueOnce(storedNotes);

    const { notes } = useNotesList();

    expect(Array.isArray(notes.value)).toBe(true);
    expect(notes.value).toHaveLength(2);
    expect(notes.value[0]).toMatchObject({ id: 1, title: 'Note 1' });
  });

  it('should handle edge case where storage is empty and return an empty array', () => {
    mockGetItem.mockReturnValueOnce(null); // nothing stored

    const { notes } = useNotesList();

    expect(Array.isArray(notes.value)).toBe(true);
    expect(notes.value).toHaveLength(0);
  });

  it('should handle null/empty scenarios gracefully without throwing', () => {
    // Simulate malformed JSON in storage
    mockGetItem.mockReturnValueOnce('not a json');

    const callUseNotesList = () => useNotesList();

    // Expect the composable not to throw and to fallback to empty array
    expect(callUseNotesList).not.toThrow();
    const { notes } = callUseNotesList();
    expect(Array.isArray(notes.value)).toBe(true);
    expect(notes.value).toHaveLength(0);
  });
});